package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Constructor;
import java.lang.reflect.Field;
import java.util.Collections;
import java.util.Map;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVRecordTest {

    private Constructor<CSVRecord> constructor;

    @BeforeEach
    void setUp() throws Exception {
        constructor = CSVRecord.class.getDeclaredConstructor(String[].class, Map.class, String.class, long.class);
        constructor.setAccessible(true);
    }

    @Test
    void testSize_withNonEmptyValuesArray() throws Exception {
        String[] values = new String[] {"a", "b", "c"};
        Map<String, Integer> mapping = Collections.emptyMap();
        CSVRecord record = constructor.newInstance(values, mapping, null, 1L);

        int size = record.size();

        assertEquals(3, size);
    }

    @Test
    void testSize_withEmptyValuesArray() throws Exception {
        String[] values = new String[0];
        Map<String, Integer> mapping = Collections.emptyMap();
        CSVRecord record = constructor.newInstance(values, mapping, null, 1L);

        int size = record.size();

        assertEquals(0, size);
    }

    @Test
    void testSize_withNullValuesArray() throws Exception {
        // Use reflection to create instance with null values array
        CSVRecord record = (CSVRecord) java.lang.reflect.Proxy.newProxyInstance(
                CSVRecord.class.getClassLoader(),
                new Class[] {CSVRecord.class},
                (proxy, method, args) -> null);
        // Instead, create instance normally and then forcibly set values to null
        String[] values = new String[] {"x"};
        Map<String, Integer> mapping = Collections.emptyMap();
        record = constructor.newInstance(values, mapping, null, 1L);

        Field valuesField = CSVRecord.class.getDeclaredField("values");
        valuesField.setAccessible(true);
        valuesField.set(record, null);

        // Now calling size() should throw NullPointerException
        try {
            record.size();
        } catch (NullPointerException e) {
            // expected
            return;
        }
        throw new AssertionError("Expected NullPointerException when values is null");
    }
}
